function AppShell({ children, onAddWish }) {
  const { user, unreadCount, refresh } = useSession();
  const navigate = useNavigate(); const toast = useToast(); const [mobileOpen, setMobileOpen] = useState(false);
  const logout = async () => { await api.post("/auth/logout", {}); await refresh(); navigate("/"); toast("Вы вышли из аккаунта"); };
  return <div className="app-layout"><aside className={`sidebar ${mobileOpen ? "is-open" : ""}`}><div className="sidebar__head"><Logo /><button className="sidebar-close" onClick={() => setMobileOpen(false)}><X /></button></div><Button icon={Plus} onClick={onAddWish} className="sidebar__add">Добавить желание</Button><nav className="sidebar__nav">{shellNav.map(({ to, icon: Icon, label, end }) => <NavLink key={to} to={to} end={end} onClick={() => setMobileOpen(false)}><Icon size={19} /><span>{label}</span>{label === "Тайный Санта" && <b>new</b>}</NavLink>)}</nav><div className="sidebar__bottom"><NavLink to="/app/notifications"><Bell size={19} /><span>Уведомления</span>{unreadCount > 0 && <i>{unreadCount}</i>}</NavLink><NavLink to="/app/settings"><Settings size={19} /><span>Настройки</span></NavLink><div className="sidebar__user"><Avatar user={user} size="sm" /><div><strong>{user.name}</strong><span>@{user.username}</span></div><button onClick={logout} title="Выйти"><LogOut size={18} /></button></div></div></aside><div className="mobile-overlay" onClick={() => setMobileOpen(false)} /><main className="app-main"><header className="mobile-app-head"><button onClick={() => setMobileOpen(true)}><Menu /></button><Logo /><Link to="/app/notifications"><Bell />{unreadCount > 0 && <i />}</Link></header>{children}</main><nav className="mobile-bottom-nav">{shellNav.slice(0, 5).map(({ to, icon: Icon, label, end }) => <NavLink key={to} to={to} end={end}><Icon /><span>{label === "Мои желания" ? "Желания" : label === "Хочу подарить" ? "Подарить" : label}</span></NavLink>)}</nav></div>;
}

function ProtectedApp() {
  const { user, loading } = useSession(); const [wishModal, setWishModal] = useState(false); const [version, setVersion] = useState(0);
  if (loading) return <LoadingScreen />;
  if (!user) return <Navigate to="/login" replace />;
  return <AppShell onAddWish={() => setWishModal(true)}><Routes><Route index element={<Dashboard onAdd={() => setWishModal(true)} version={version} />} /><Route path="wishes" element={<WishesPage onAdd={() => setWishModal(true)} version={version} />} /><Route path="ideas" element={<IdeasPage appMode />} /><Route path="friends" element={<FriendsPage />} /><Route path="gifts" element={<GiftsPage />} /><Route path="notifications" element={<NotificationsPage />} /><Route path="settings" element={<SettingsPage />} /><Route path="santa" element={<SantaPage />} /><Route path="santa/:id" element={<SantaDetailPage />} /></Routes>{wishModal && <WishModal onClose={() => setWishModal(false)} onSaved={() => { setWishModal(false); setVersion((v) => v + 1); }} />}</AppShell>;
}

function PageTitle({ eyebrow, title, text, action }) { return <div className="app-page-title"><div>{eyebrow && <span className="eyebrow">{eyebrow}</span>}<h1>{title}</h1>{text && <p>{text}</p>}</div>{action}</div>; }

function Dashboard({ onAdd, version }) {
  const { user } = useSession(); const { data, loading, error, reload } = useAsync(() => api.get("/dashboard"), [version]); const toast = useToast();
  if (loading) return <LoadingScreen compact />;
  if (error) return <EmptyState title="Не удалось загрузить обзор" text={error.message} action={<Button onClick={() => reload().catch(() => {})}>Повторить</Button>} />;
  const active = data.wishes.filter((wish) => wish.status === "active");
  const copyProfile = async () => { await navigator.clipboard.writeText(`${window.location.origin}/u/${user.username}`); toast("Ссылка на вишлист скопирована"); };
  return <div className="app-page dashboard"><PageTitle eyebrow={new Intl.DateTimeFormat("ru-RU", { weekday: "long", day: "numeric", month: "long" }).format(new Date())} title={`Привет, ${user.name.split(" ")[0]}!`} text="Что сегодня хочется добавить в жизнь?" action={<Button variant="outline" icon={Share2} onClick={copyProfile}>Поделиться</Button>} /><section className="dashboard-hero"><div><span>В вашем вишлисте</span><strong>{active.length}</strong><p>{active.length === 1 ? "активное желание" : "активных желаний"} в {data.lists.length} {data.lists.length === 1 ? "списке" : "списках"}</p><Button icon={Plus} onClick={onAdd}>Добавить мечту</Button></div><div className="dashboard-hero__collage">{active.slice(0, 3).map((wish, index) => <img key={wish.id} src={wish.imageUrl || `https://images.unsplash.com/photo-1549465220-1a8b9238cd48?auto=format&fit=crop&w=500&q=80&sig=${index}`} alt="" />)}{active.length === 0 && <Gift size={80} />}</div></section><div className="dashboard-grid"><section className="panel panel--wide"><div className="panel__head"><div><h2>Последние желания</h2><span>Ваш список выглядит чудесно</span></div><Link to="/app/wishes">Все желания <ArrowRight size={16} /></Link></div>{active.length ? <div className="compact-wishes">{active.slice(0, 4).map((wish) => <Link to="/app/wishes" className="compact-wish" key={wish.id}><img src={wish.imageUrl || "/gift-placeholder.svg"} alt="" /><div><strong>{wish.title}</strong><span>{formatMoney(wish.price, wish.currency)}</span></div><Priority value={wish.priority} /></Link>)}</div> : <EmptyState title="Пока здесь тихо" text="Добавьте первую мечту — даже самую маленькую." action={<Button onClick={onAdd} icon={Plus}>Добавить</Button>} />}</section><section className="panel"><div className="panel__head"><div><h2>Скоро праздник</h2><span>Дни рождения друзей</span></div><CalendarDays size={19} /></div><div className="birthday-list">{data.birthdays.length ? data.birthdays.map((friend) => <Link to={`/u/${friend.username}`} key={friend.id}><Avatar user={friend} size="sm" /><div><strong>{friend.name}</strong><span>{formatDate(friend.birthday)}</span></div><ArrowRight size={16} /></Link>) : <p className="muted">Подпишитесь на друзей, чтобы видеть даты.</p>}</div><Link className="panel-link" to="/app/friends"><UserPlus size={16} /> Найти друзей</Link></section><section className="panel panel--wide"><div className="panel__head"><div><h2>Ваши списки</h2><span>Разложите мечты по настроению</span></div><Link to="/app/wishes">Управлять <ArrowRight size={16} /></Link></div><div className="list-strip">{data.lists.map((list) => <article className={`mini-list mini-list--${list.color}`} key={list.id}><div><ListPlus size={18} /><span>{list.privacy === "private" ? <LockKeyhole size={13} /> : null}{list.wishCount} желаний</span></div><strong>{list.title}</strong><p>{list.description || "Ваш личный список"}</p></article>)}</div></section><section className="panel"><div className="panel__head"><div><h2>Тайный Санта</h2><span>Игры с друзьями</span></div><PartyPopper size={19} /></div>{data.games[0] ? <Link className="santa-mini" to={`/app/santa/${data.games[0].id}`}><span className="santa-mini__icon"><Gift /></span><div><strong>{data.games[0].title}</strong><span>{data.games[0].participantCount} участников · {data.games[0].status === "drawn" ? "пары готовы" : "сбор участников"}</span></div><ArrowRight size={16} /></Link> : <EmptyState icon={PartyPopper} title="Соберите компанию" text="Код приглашения, подсказки и честная жеребьёвка." action={<Link className="button button--outline" to="/app/santa"><span>Создать игру</span></Link>} />}</section></div></div>;
}

function Priority({ value }) { return <span className="priority" title={`Важность: ${value} из 3`}>{[1, 2, 3].map((item) => <i key={item} className={item <= value ? "is-on" : ""} />)}</span>; }

function WishCard({ wish, owner = false, onChanged, profile }) {
  const toast = useToast(); const [menu, setMenu] = useState(false); const [busy, setBusy] = useState(false);
  const reserve = async () => { setBusy(true); try { const result = await api.post(`/wishes/${wish.id}/reserve`, {}); toast(result.reserved ? "Подарок забронирован — владелец не узнает кем" : "Бронь снята"); onChanged?.(); } catch (error) { toast(error.message, "error"); } finally { setBusy(false); } };
  const remove = async () => { if (!window.confirm("Удалить это желание?")) return; try { await api.delete(`/wishes/${wish.id}`); toast("Желание удалено"); onChanged?.(); } catch (error) { toast(error.message, "error"); } };
  const fulfilled = async () => { try { await api.post(`/wishes/${wish.id}/fulfilled`, {}); toast(wish.status === "fulfilled" ? "Желание снова активно" : "Отмечено исполненным ✦"); onChanged?.(); } catch (error) { toast(error.message, "error"); } };
  const share = async () => { await navigator.clipboard.writeText(wish.url || `${window.location.origin}/u/${profile?.username || ""}`); toast("Ссылка скопирована"); };
  return <article className={`wish-card ${wish.status === "fulfilled" ? "is-fulfilled" : ""}`}><div className="wish-card__image">{wish.imageUrl ? <img src={wish.imageUrl} alt="" /> : <span><Gift size={36} /></span>}<Priority value={wish.priority} />{wish.status === "fulfilled" && <div className="fulfilled-badge"><Check /> Исполнено</div>}</div><div className="wish-card__body"><div className="wish-card__top"><span>{formatMoney(wish.price, wish.currency)}</span><button onClick={() => setMenu(!menu)}><MoreHorizontal /></button>{menu && <div className="card-menu"><button onClick={share}><Share2 /> Поделиться</button>{wish.url && <a href={wish.url} target="_blank" rel="noreferrer"><ExternalLink /> Открыть магазин</a>}{owner && <><button onClick={fulfilled}><PackageCheck /> {wish.status === "fulfilled" ? "Вернуть в активные" : "Желание исполнено"}</button><button className="danger" onClick={remove}><Trash2 /> Удалить</button></>}</div>}</div><h3>{wish.title}</h3><p>{wish.description || "Без дополнительного описания"}</p>{owner ? <div className="wish-card__owner-meta">{wish.privacy === "private" ? <span><LockKeyhole /> Только вам</span> : <span><Eye /> Виден друзьям</span>}{wish.reservationCount > 0 && <span><Gift /> Кто-то готовит подарок</span>}</div> : <Button variant={wish.reservedByMe ? "reserved" : "outline"} loading={busy} icon={wish.reservedByMe ? Check : Gift} onClick={reserve} disabled={wish.status !== "active"}>{wish.reservedByMe ? "Забронировано вами" : wish.reservationCount > 0 && !wish.allowMultiple ? "Уже забронировано" : "Забронировать"}</Button>}</div></article>;
}

function WishesPage({ onAdd, version }) {
  const { user } = useSession(); const toast = useToast(); const { data, loading, reload } = useAsync(() => api.get("/dashboard"), [version]); const [selected, setSelected] = useState("all"); const [listModal, setListModal] = useState(false);
  if (loading) return <LoadingScreen compact />;
  const wishes = selected === "all" ? data.wishes : data.wishes.filter((wish) => wish.listIds.includes(selected));
  const share = async () => { const url = selected === "all" ? `${window.location.origin}/u/${user.username}` : `${window.location.origin}/s/${data.lists.find((list) => list.id === selected)?.shareToken}`; await navigator.clipboard.writeText(url); toast("Ссылка на список скопирована"); };
  return <div className="app-page wishes-page"><PageTitle eyebrow="Личная коллекция" title="Мои желания" text={`${data.wishes.filter((wish) => wish.status === "active").length} активных · ${data.wishes.filter((wish) => wish.status === "fulfilled").length} исполнено`} action={<div className="page-actions"><Button variant="outline" icon={Share2} onClick={share}>Поделиться</Button><Button icon={Plus} onClick={onAdd}>Добавить</Button></div>} /><div className="list-tabs"><button className={selected === "all" ? "active" : ""} onClick={() => setSelected("all")}><Heart size={16} /> Все <span>{data.wishes.length}</span></button>{data.lists.map((list) => <button className={selected === list.id ? "active" : ""} key={list.id} onClick={() => setSelected(list.id)}>{list.privacy === "private" && <LockKeyhole size={14} />}{list.title} <span>{list.wishCount}</span></button>)}<button className="list-tabs__add" onClick={() => setListModal(true)}><Plus size={16} /> Новый список</button></div>{wishes.length ? <div className="wish-grid">{wishes.map((wish) => <WishCard key={wish.id} wish={wish} owner profile={user} onChanged={reload} />)}</div> : <EmptyState icon={Heart} title="В этом списке пока пусто" text="Добавьте то, что действительно порадует." action={<Button icon={Plus} onClick={onAdd}>Добавить желание</Button>} />}{listModal && <ListModal onClose={() => setListModal(false)} onSaved={() => { setListModal(false); reload(); }} />}</div>;
}

function Modal({ children, onClose, wide = false }) { useEffect(() => { const close = (event) => event.key === "Escape" && onClose(); document.addEventListener("keydown", close); document.body.classList.add("modal-open"); return () => { document.removeEventListener("keydown", close); document.body.classList.remove("modal-open"); }; }, [onClose]); return <div className="modal-backdrop" onMouseDown={(event) => event.target === event.currentTarget && onClose()}><div className={`modal ${wide ? "modal--wide" : ""}`}>{children}<button className="modal__close" onClick={onClose}><X /></button></div></div>; }

function ListModal({ onClose, onSaved }) {
  const toast = useToast(); const [loading, setLoading] = useState(false); const [form, setForm] = useState({ title: "", description: "", privacy: "public", occasionDate: "", color: "coral" });
  const submit = async (event) => { event.preventDefault(); setLoading(true); try { await api.post("/lists", { ...form, occasionDate: form.occasionDate || null }); toast("Новый список создан"); onSaved(); } catch (error) { toast(error.message, "error"); } finally { setLoading(false); } };
  return <Modal onClose={onClose}><form className="modal-form" onSubmit={submit}><div className="modal-heading"><span className="modal-icon"><ListPlus /></span><div><span className="eyebrow">Новая глава</span><h2>Создать список</h2><p>Для отдельного события, настроения или большой мечты.</p></div></div><label><span>Название</span><input autoFocus required placeholder="Например, Новоселье" value={form.title} onChange={(event) => setForm({ ...form, title: event.target.value })} /></label><label><span>Описание</span><textarea rows={3} placeholder="Расскажите друзьям о списке" value={form.description} onChange={(event) => setForm({ ...form, description: event.target.value })} /></label><div className="form-row"><label><span>Дата события</span><input type="date" value={form.occasionDate} onChange={(event) => setForm({ ...form, occasionDate: event.target.value })} /></label><label><span>Кто увидит</span><select value={form.privacy} onChange={(event) => setForm({ ...form, privacy: event.target.value })}><option value="public">Все</option><option value="followers">Подписчики</option><option value="link">Только по ссылке</option><option value="private">Только я</option></select></label></div><fieldset className="color-picker"><legend>Цвет обложки</legend>{["coral", "blue", "lime", "sun", "ink"].map((color) => <button type="button" className={`${color} ${form.color === color ? "active" : ""}`} onClick={() => setForm({ ...form, color })} key={color}>{form.color === color && <Check />}</button>)}</fieldset><div className="modal-actions"><Button type="button" variant="ghost" onClick={onClose}>Отмена</Button><Button type="submit" loading={loading}>Создать список</Button></div></form></Modal>;
}

function WishModal({ onClose, onSaved }) {
  const toast = useToast(); const { data, loading: listsLoading } = useAsync(() => api.get("/dashboard"), []); const [step, setStep] = useState("link"); const [loading, setLoading] = useState(false); const [metaLoading, setMetaLoading] = useState(false); const [form, setForm] = useState({ title: "", description: "", url: "", imageUrl: "", price: "", currency: "RUB", priority: 2, privacy: "inherit", allowMultiple: false, listIds: [] });
  useEffect(() => { if (data?.lists?.[0] && form.listIds.length === 0) setForm((current) => ({ ...current, listIds: [data.lists[0].id] })); }, [data]); // eslint-disable-line react-hooks/exhaustive-deps
  const recognize = async () => { if (!form.url) { setStep("details"); return; } setMetaLoading(true); try { const meta = await api.post("/metadata", { url: form.url }); setForm((current) => ({ ...current, ...meta, price: meta.price ?? current.price, currency: ["RUB", "USD", "EUR", "KZT", "BYN"].includes(meta.currency) ? meta.currency : "RUB" })); setStep("details"); toast(meta.title ? "Карточка заполнена по ссылке" : "Заполните детали вручную"); } catch (error) { setStep("details"); toast(error.message, "error"); } finally { setMetaLoading(false); } };
  const submit = async (event) => { event.preventDefault(); setLoading(true); try { await api.post("/wishes", { ...form, price: form.price === "" ? null : Number(form.price) }); toast("Желание добавлено ✦"); onSaved(); } catch (error) { toast(error.message, "error"); } finally { setLoading(false); } };
  const toggleList = (id) => setForm((current) => ({ ...current, listIds: current.listIds.includes(id) ? current.listIds.filter((item) => item !== id) : [...current.listIds, id] }));
  return <Modal onClose={onClose} wide><form className="modal-form wish-form" onSubmit={submit}><div className="modal-heading"><span className="modal-icon"><Heart fill="currentColor" /></span><div><span className="eyebrow">Новое желание</span><h2>{step === "link" ? "Добавим мечту" : "Проверьте карточку"}</h2><p>{step === "link" ? "Вставьте ссылку на товар или добавьте всё вручную." : "Чем точнее детали, тем проще друзьям."}</p></div></div>{step === "link" ? <div className="link-step"><label className="link-input"><Link2 /><input autoFocus type="url" placeholder="https://магазин.ru/то-самое" value={form.url} onChange={(event) => setForm({ ...form, url: event.target.value })} /></label><Button type="button" onClick={recognize} loading={metaLoading}>Продолжить</Button><button type="button" className="manual-link" onClick={() => setStep("details")}>У меня нет ссылки — заполнить вручную</button><div className="recognition-note"><WandSparkles /><div><strong>Умное заполнение</strong><span>Попробуем распознать название, фото и цену на странице магазина.</span></div></div></div> : <><div className="wish-form__grid"><div className="image-preview"><div>{form.imageUrl ? <img src={form.imageUrl} alt="Предпросмотр" /> : <><Image size={35} /><span>Фото желания</span></>}</div><label><Image size={16} /> Ссылка на фото<input type="url" value={form.imageUrl} onChange={(event) => setForm({ ...form, imageUrl: event.target.value })} /></label></div><div className="wish-fields"><label><span>Название</span><input autoFocus required value={form.title} placeholder="Что вы хотите?" onChange={(event) => setForm({ ...form, title: event.target.value })} /></label><label><span>Комментарий для друзей</span><textarea rows={3} value={form.description} placeholder="Размер, цвет, важные детали…" onChange={(event) => setForm({ ...form, description: event.target.value })} /></label><div className="form-row form-row--price"><label><span>Цена</span><input type="number" min="0" value={form.price} placeholder="0" onChange={(event) => setForm({ ...form, price: event.target.value })} /></label><label><span>Валюта</span><select value={form.currency} onChange={(event) => setForm({ ...form, currency: event.target.value })}>{["RUB", "USD", "EUR", "KZT", "BYN"].map((currency) => <option key={currency}>{currency}</option>)}</select></label><label><span>Важность</span><div className="priority-picker">{[1, 2, 3].map((item) => <button type="button" className={item <= form.priority ? "active" : ""} onClick={() => setForm({ ...form, priority: item })} key={item}><Star fill="currentColor" /></button>)}</div></label></div></div></div><fieldset className="list-choice"><legend>Добавить в списки</legend>{listsLoading ? <LoadingScreen compact /> : data.lists.map((list) => <label key={list.id}><input type="checkbox" checked={form.listIds.includes(list.id)} onChange={() => toggleList(list.id)} /><span className={`list-dot list-dot--${list.color}`} /><span>{list.title}</span><small>{list.wishCount} желаний</small><Check /></label>)}</fieldset><div className="wish-settings"><label><input type="checkbox" checked={form.privacy === "private"} onChange={(event) => setForm({ ...form, privacy: event.target.checked ? "private" : "inherit" })} /><span><LockKeyhole /> Секретное желание<small>Видно только вам</small></span></label><label><input type="checkbox" checked={form.allowMultiple} onChange={(event) => setForm({ ...form, allowMultiple: event.target.checked })} /><span><Gift /> Можно подарить несколько<small>Например, сертификаты</small></span></label></div><div className="modal-actions"><Button type="button" variant="ghost" onClick={() => setStep("link")} icon={ArrowLeft}>Назад</Button><Button type="submit" loading={loading} icon={Heart}>Добавить желание</Button></div></>}</form></Modal>;
}

function IdeasPage({ appMode = false }) {
  const { user } = useSession(); const toast = useToast(); const [search, setSearch] = useState(""); const [category, setCategory] = useState(""); const [selectedIdea, setSelectedIdea] = useState(null); const { data, loading } = useAsync(() => api.get(`/ideas?category=${encodeURIComponent(category)}&search=${encodeURIComponent(search)}`), [category, search]);
  const content = <><div className="ideas-hero"><span className="eyebrow"><WandSparkles size={15} /> Отобрано с любопытством</span><h1>Идеи, от которых<br /><em>что-то ёкает</em></h1><p>Не безликий каталог товаров, а поводы заметить: «Да, вот этого мне и хотелось».</p><label className="ideas-search"><Search /><input placeholder="Керамика, музыка, впечатления…" value={search} onChange={(event) => setSearch(event.target.value)} /><kbd>⌘ K</kbd></label></div>{loading ? <LoadingScreen compact /> : <><div className="category-row"><button className={!category ? "active" : ""} onClick={() => setCategory("")}>Всё <span>{data.categories.reduce((sum, item) => sum + item.count, 0)}</span></button>{data.categories.map((item) => <button className={category === item.name ? "active" : ""} onClick={() => setCategory(item.name)} key={item.name}>{item.name} <span>{item.count}</span></button>)}</div><div className="ideas-grid">{data.ideas.map((idea, index) => <article className={`idea-card idea-card--${index % 5}`} key={idea.id}><div className="idea-card__image"><img src={idea.imageUrl} alt="" /><span>{idea.badge}</span><button onClick={() => user ? setSelectedIdea(idea) : toast("Войдите, чтобы сохранить идею", "error")}><Heart /></button></div><div className="idea-card__copy"><small>{idea.category}</small><h3>{idea.title}</h3><p>{idea.description}</p><strong>{formatMoney(idea.price, idea.currency)}</strong></div></article>)}</div></>}{selectedIdea && <SaveIdeaModal idea={selectedIdea} onClose={() => setSelectedIdea(null)} />}</>;
  if (appMode) return <div className="app-page ideas-page">{content}</div>;
  return <div className="public-ideas"><LandingHeader /><main>{content}</main><footer className="landing-footer"><Logo /><p>Списки желаний, которые приятно исполнять.</p><span>© 2026 Rollwish</span></footer></div>;
}

function SaveIdeaModal({ idea, onClose }) { const toast = useToast(); const { data, loading } = useAsync(() => api.get("/dashboard"), []); const [listId, setListId] = useState(""); const [busy, setBusy] = useState(false); useEffect(() => { if (data?.lists?.[0]) setListId(data.lists[0].id); }, [data]); const save = async () => { setBusy(true); try { await api.post(`/ideas/${idea.id}/save`, { listId }); toast("Идея сохранена в ваш список"); onClose(); } catch (error) { toast(error.message, "error"); } finally { setBusy(false); } }; return <Modal onClose={onClose}><div className="save-idea"><img src={idea.imageUrl} alt="" /><span className="eyebrow">Сохранить идею</span><h2>{idea.title}</h2><p>{idea.description}</p>{loading ? <LoadingScreen compact /> : <label><span>Выберите список</span><select value={listId} onChange={(event) => setListId(event.target.value)}>{data.lists.map((list) => <option value={list.id} key={list.id}>{list.title}</option>)}</select></label>}<div className="modal-actions"><Button variant="ghost" onClick={onClose}>Отмена</Button><Button icon={Heart} onClick={save} loading={busy}>Сохранить</Button></div></div></Modal>; }

function FriendsPage() { const [search, setSearch] = useState(""); const { data, loading, reload } = useAsync(() => api.get(`/people?search=${encodeURIComponent(search)}`), [search]); const toast = useToast(); const follow = async (person) => { try { const result = await api.post(`/profile/${person.username}/follow`, {}); toast(result.following ? `Вы подписались на ${person.name}` : "Подписка отменена"); reload(); } catch (error) { toast(error.message, "error"); } }; return <div className="app-page friends-page"><PageTitle eyebrow="Люди рядом" title="Друзья и их мечты" text="Подпишитесь, чтобы не пропускать важные даты и новые желания." /><label className="app-search"><Search /><input placeholder="Имя или @профиль" value={search} onChange={(event) => setSearch(event.target.value)} /></label>{loading ? <LoadingScreen compact /> : <div className="people-grid">{data.people.map((person) => <article className="person-card" key={person.id}><Link to={`/u/${person.username}`}><Avatar user={person} size="lg" /><span className="person-card__count"><Heart size={14} fill="currentColor" /> {person.wishCount}</span><h3>{person.name}</h3><small>@{person.username}</small><p>{person.bio || "Пока без описания"}</p></Link><Button variant={person.isFollowing ? "soft" : "outline"} icon={person.isFollowing ? Check : UserPlus} onClick={() => follow(person)}>{person.isFollowing ? "Вы подписаны" : "Подписаться"}</Button></article>)}</div>}</div>; }

function GiftsPage() { const { data, loading } = useAsync(() => api.get("/dashboard"), []); if (loading) return <LoadingScreen compact />; return <div className="app-page"><PageTitle eyebrow="Секретный план" title="Хочу подарить" text="Здесь видны ваши брони. Владельцы желаний — ничего не узнают." />{data.reservations.length ? <div className="reservation-list">{data.reservations.map((item) => <article key={item.id}><img src={item.image_url || "/gift-placeholder.svg"} alt="" /><div><small>Подарок для <Link to={`/u/${item.owner_username}`}>{item.owner_name}</Link></small><h3>{item.title}</h3><span>{formatMoney(item.price, item.currency)}</span></div><Link className="button button--outline" to={`/u/${item.owner_username}`}><span>Открыть список</span><ArrowRight size={17} /></Link></article>)}</div> : <EmptyState icon={Gift} title="Вы пока ничего не забронировали" text="Загляните в вишлисты друзей и выберите подарок." action={<Link className="button button--primary" to="/app/friends"><span>Найти друзей</span></Link>} />}</div>; }

function NotificationsPage() { const { refresh } = useSession(); const { data, loading, reload } = useAsync(() => api.get("/notifications"), []); useEffect(() => { api.post("/notifications/read", {}).then(() => refresh()); }, [refresh]); if (loading) return <LoadingScreen compact />; const icons = { reservation: Gift, follow: UserPlus, santa: PartyPopper, "santa-message": MessageCircle, welcome: Sparkles }; return <div className="app-page notifications-page"><PageTitle eyebrow="В курсе важного" title="Уведомления" text="Сюрпризы останутся скрыты, а важные события — нет." />{data.notifications.length ? <div className="notification-list">{data.notifications.map((item) => { const Icon = icons[item.type] || Bell; return <Link to={item.href || "#"} key={item.id} className={!item.readAt ? "is-unread" : ""}><span><Icon /></span><div><strong>{item.title}</strong><p>{item.body}</p><small>{formatDate(item.createdAt, { hour: "2-digit", minute: "2-digit" })}</small></div><ArrowRight /></Link>; })}</div> : <EmptyState icon={Bell} title="Пока тихо" text="Здесь появятся новые подписки и важные события." />}<button className="visually-hidden" onClick={reload}>Обновить</button></div>; }

function SettingsPage() { const { user, refresh } = useSession(); const toast = useToast(); const [form, setForm] = useState({ name: user.name, username: user.username, bio: user.bio || "", birthday: user.birthday ? String(user.birthday).slice(0, 10) : "", avatarUrl: user.avatarUrl || "" }); const [loading, setLoading] = useState(false); const submit = async (event) => { event.preventDefault(); setLoading(true); try { await api.patch("/me", { ...form, birthday: form.birthday || null }); await refresh(); toast("Профиль обновлён"); } catch (error) { toast(error.message, "error"); } finally { setLoading(false); } }; return <div className="app-page settings-page"><PageTitle eyebrow="Личное пространство" title="Настройки профиля" text="Эту информацию увидят друзья рядом с вашим вишлистом." /><form className="settings-form panel" onSubmit={submit}><div className="avatar-editor"><Avatar user={{ ...user, avatarUrl: form.avatarUrl }} size="xl" /><div><strong>Фото профиля</strong><span>Укажите публичную ссылку на изображение</span></div></div><label><span>Ссылка на фото</span><input type="url" value={form.avatarUrl} placeholder="https://…" onChange={(event) => setForm({ ...form, avatarUrl: event.target.value })} /></label><div className="form-row"><label><span>Имя</span><input required value={form.name} onChange={(event) => setForm({ ...form, name: event.target.value })} /></label><label><span>Адрес профиля</span><div className="input-prefix"><span>rollwish.ru/u/</span><input required pattern="[a-z0-9-]{3,32}" value={form.username} onChange={(event) => setForm({ ...form, username: event.target.value.toLowerCase() })} /></div></label></div><label><span>О себе</span><textarea rows={4} maxLength={300} value={form.bio} placeholder="Что вам нравится?" onChange={(event) => setForm({ ...form, bio: event.target.value })} /></label><label className="short-field"><span>День рождения</span><input type="date" value={form.birthday} onChange={(event) => setForm({ ...form, birthday: event.target.value })} /></label><div className="settings-save"><Button type="submit" loading={loading}>Сохранить изменения</Button></div></form></div>; }

function PublicProfile({ shared = false }) { const params = useParams(); const { user } = useSession(); const toast = useToast(); const endpoint = shared ? `/shared/${params.token}` : `/profile/${params.username}`; const { data, loading, error, reload } = useAsync(() => api.get(endpoint), [endpoint]); const [selected, setSelected] = useState("all"); if (loading) return <LoadingScreen />; if (error) return <div className="not-found"><Logo /><Gift /><h1>Такой список не нашёлся</h1><p>{error.message}</p><Link className="button button--primary" to="/"><span>На главную</span></Link></div>; const lists = shared ? [data.list] : data.lists; const wishes = shared ? data.wishes : selected === "all" ? data.wishes : data.wishes.filter((wish) => wish.listIds.includes(selected)); const follow = async () => { if (!user) return window.location.assign("/login"); try { const result = await api.post(`/profile/${data.profile.username}/follow`, {}); toast(result.following ? "Вы подписались" : "Подписка отменена"); reload(); } catch (e) { toast(e.message, "error"); } }; const share = async () => { await navigator.clipboard.writeText(window.location.href); toast("Ссылка скопирована"); }; return <div className="public-profile"><header><Logo /><div>{user ? <Link className="button button--soft" to="/app"><span>Мой вишлист</span></Link> : <><Link className="text-link" to="/login">Войти</Link><Link className="button button--primary" to="/register"><span>Создать свой</span></Link></>}</div></header><main><section className="profile-cover"><div className="profile-cover__pattern" /><Avatar user={data.profile} size="xl" /><div className="profile-cover__copy"><span className="eyebrow">Вишлист</span><h1>{data.profile.name}</h1><p>{data.profile.bio || "Здесь живут желания, которым пора сбыться."}</p><div className="profile-stats">{data.profile.birthday && <span><CalendarDays /> {formatDate(data.profile.birthday)}</span>}{!shared && <><span><Users /> {data.followersCount} подписчиков</span><span><Heart /> {data.wishes.length} желаний</span></>}</div></div><div className="profile-cover__actions"><Button variant="outline" icon={Share2} onClick={share}>Поделиться</Button>{!data.isOwner && !shared && <Button icon={data.isFollowing ? Check : UserPlus} variant={data.isFollowing ? "soft" : "primary"} onClick={follow}>{data.isFollowing ? "Вы подписаны" : "Подписаться"}</Button>}</div></section>{!shared && <div className="public-list-tabs"><button className={selected === "all" ? "active" : ""} onClick={() => setSelected("all")}>Все желания</button>{lists.map((list) => <button className={selected === list.id ? "active" : ""} onClick={() => setSelected(list.id)} key={list.id}>{list.title}<span>{list.wishCount}</span></button>)}</div>}{shared && <div className={`shared-list-head shared-list-head--${data.list.color}`}><ListPlus /><div><span>Отдельный список</span><h2>{data.list.title}</h2><p>{data.list.description}</p></div></div>}{wishes.length ? <div className="wish-grid">{wishes.map((wish) => <WishCard key={wish.id} wish={wish} owner={data.isOwner} profile={data.profile} onChanged={reload} />)}</div> : <EmptyState icon={Heart} title="В этом списке пока пусто" text="Загляните чуть позже — новая мечта наверняка появится." />}</main><footer><Logo /><span>Создано с мечтами в Rollwish</span><Link to="/register">Собрать свой список <ArrowRight size={16} /></Link></footer></div>; }

function SantaPage() { const toast = useToast(); const { data, loading, reload } = useAsync(() => api.get("/santa"), []); const [mode, setMode] = useState(null); if (loading) return <LoadingScreen compact />; return <div className="app-page santa-page"><PageTitle eyebrow="Подарки инкогнито" title="Тайный Санта" text="Вся игра — от приглашения до анонимного сообщения — в одном месте." action={<div className="page-actions"><Button variant="outline" icon={Link2} onClick={() => setMode("join")}>Войти по коду</Button><Button icon={Plus} onClick={() => setMode("create")}>Создать игру</Button></div>} /><section className="santa-app-banner"><div><span><PartyPopper /> Как это работает</span><h2>Соберите компанию.<br />Мы тихо всё разыграем.</h2><p>Участники оставляют подсказки, а после жеребьёвки каждый видит только своего подопечного.</p></div><div className="santa-banner-gift"><Gift /><span>?</span></div></section>{data.games.length ? <div className="game-grid">{data.games.map((game) => <Link className={`game-card ${game.status === "drawn" ? "game-card--drawn" : ""}`} to={`/app/santa/${game.id}`} key={game.id}><div><span>{game.status === "drawn" ? <Check /> : <Users />}{game.status === "drawn" ? "Пары готовы" : "Собираем участников"}</span><strong>{game.participantCount}</strong></div><h3>{game.title}</h3><p>{game.description || "Праздничный обмен подарками"}</p><footer><span><CalendarDays /> {formatDate(game.event_date)}</span><span>{formatMoney(game.budget, game.currency)}</span><ArrowRight /></footer></Link>)}</div> : <EmptyState icon={PartyPopper} title="Пока ни одной игры" text="Создайте свою или присоединитесь по коду приглашения." action={<Button onClick={() => setMode("create")}>Создать игру</Button>} />}{mode && <SantaModal mode={mode} onClose={() => setMode(null)} onSaved={() => { setMode(null); reload(); toast(mode === "create" ? "Игра создана — зовите друзей" : "Вы в игре!"); }} />}</div>; }

function SantaModal({ mode, onClose, onSaved }) { const toast = useToast(); const [loading, setLoading] = useState(false); const [form, setForm] = useState(mode === "join" ? { code: "", giftHints: "" } : { title: "", description: "", eventDate: "", budget: "3000", currency: "RUB", giftHints: "" }); const submit = async (event) => { event.preventDefault(); setLoading(true); try { if (mode === "join") await api.post("/santa/join", form); else await api.post("/santa", { ...form, eventDate: form.eventDate || null, budget: form.budget ? Number(form.budget) : null }); onSaved(); } catch (error) { toast(error.message, "error"); } finally { setLoading(false); } }; return <Modal onClose={onClose}><form className="modal-form" onSubmit={submit}><div className="modal-heading"><span className="modal-icon modal-icon--dark"><PartyPopper /></span><div><span className="eyebrow">{mode === "join" ? "Есть приглашение" : "Новая игра"}</span><h2>{mode === "join" ? "Войти по коду" : "Создать Тайного Санту"}</h2><p>{mode === "join" ? "Код пришлёт организатор игры." : "Название, дата и мягкое ограничение бюджета."}</p></div></div>{mode === "join" ? <label><span>Код приглашения</span><input autoFocus required className="code-input" placeholder="SNOW26" value={form.code} onChange={(event) => setForm({ ...form, code: event.target.value.toUpperCase() })} /></label> : <><label><span>Название</span><input autoFocus required placeholder="Тайный Санта нашей команды" value={form.title} onChange={(event) => setForm({ ...form, title: event.target.value })} /></label><label><span>Описание</span><textarea rows={3} placeholder="Правила и настроение игры" value={form.description} onChange={(event) => setForm({ ...form, description: event.target.value })} /></label><div className="form-row"><label><span>Дата обмена</span><input type="date" value={form.eventDate} onChange={(event) => setForm({ ...form, eventDate: event.target.value })} /></label><label><span>Бюджет</span><input type="number" min="1" value={form.budget} onChange={(event) => setForm({ ...form, budget: event.target.value })} /></label></div></>}<label><span>Подсказка вашему Санте</span><textarea rows={3} placeholder="Что любите, чего избегать, аллергии…" value={form.giftHints} onChange={(event) => setForm({ ...form, giftHints: event.target.value })} /></label><div className="modal-actions"><Button type="button" variant="ghost" onClick={onClose}>Отмена</Button><Button type="submit" loading={loading}>{mode === "join" ? "Присоединиться" : "Создать игру"}</Button></div></form></Modal>; }

function SantaDetailPage() { const { id } = useParams(); const toast = useToast(); const { data, loading, error, reload } = useAsync(() => api.get(`/santa/${id}`), [id]); const [hints, setHints] = useState(""); const [message, setMessage] = useState(""); const [drawing, setDrawing] = useState(false); useEffect(() => { if (data) setHints(data.game.giftHints || ""); }, [data]); if (loading) return <LoadingScreen compact />; if (error) return <EmptyState title="Игра не найдена" text={error.message} />; const copyCode = async () => { await navigator.clipboard.writeText(data.game.inviteCode); toast("Код приглашения скопирован"); }; const draw = async () => { if (!window.confirm("Провести жеребьёвку? После этого добавить участников нельзя.")) return; setDrawing(true); try { await api.post(`/santa/${id}/draw`, {}); toast("Пары готовы. Никому не рассказываем!"); reload(); } catch (e) { toast(e.message, "error"); } finally { setDrawing(false); } }; const saveHints = async () => { try { await api.patch(`/santa/${id}/me`, { giftHints: hints }); toast("Подсказка сохранена"); } catch (e) { toast(e.message, "error"); } }; const send = async (event) => { event.preventDefault(); try { await api.post(`/santa/${id}/message`, { body: message }); setMessage(""); reload(); } catch (e) { toast(e.message, "error"); } }; return <div className="app-page santa-detail"><Link className="back-link" to="/app/santa"><ArrowLeft /> Ко всем играм</Link><section className="game-head"><div><span className={`status-pill status-pill--${data.game.status}`}>{data.game.status === "drawn" ? <Check /> : <Users />}{data.game.status === "drawn" ? "Пары разыграны" : "Сбор участников"}</span><h1>{data.game.title}</h1><p>{data.game.description}</p><div><span><CalendarDays /> {formatDate(data.game.eventDate)}</span><span><Gift /> {formatMoney(data.game.budget, data.game.currency)}</span></div></div><div className="invite-code"><small>Код приглашения</small><strong>{data.game.inviteCode}</strong><button onClick={copyCode}><Copy /> Копировать</button></div></section>{data.game.status === "collecting" ? <div className="santa-detail-grid"><section className="panel panel--wide"><div className="panel__head"><div><h2>Участники</h2><span>{data.participants.length} в игре · минимум 3</span></div>{data.game.isOwner && <Button icon={PartyPopper} loading={drawing} onClick={draw}>Провести жеребьёвку</Button>}</div><div className="participants">{data.participants.map((person, index) => <div key={person.id}><Avatar user={person} /><strong>{person.name}</strong><span>{index === 0 && data.game.isOwner ? "Организатор" : "Участник"}</span></div>)}<button onClick={copyCode}><Plus /><strong>Позвать ещё</strong><span>Скопировать код</span></button></div></section><section className="panel"><div className="panel__head"><div><h2>Подсказка Санте</h2><span>Её увидит только даритель</span></div><Sparkles /></div><textarea rows={6} placeholder="Люблю бумажные книги…" value={hints} onChange={(event) => setHints(event.target.value)} /><Button variant="outline" onClick={saveHints}>Сохранить подсказку</Button></section></div> : <div className="assignment-layout"><section className="assignment-card"><span className="eyebrow eyebrow--light">Тс-с, ваш подопечный</span><Avatar user={data.assignment.user} size="xl" /><h2>{data.assignment.user.name}</h2><Link to={`/u/${data.assignment.user.username}`}>@{data.assignment.user.username}</Link><div className="hint-paper"><Sparkles /><div><small>Подсказка</small><p>{data.assignment.giftHints || "Подсказки нет — загляните в вишлист."}</p></div></div><Link className="button button--paper" to={`/u/${data.assignment.user.username}`}><span>Открыть весь вишлист</span><ArrowRight /></Link></section><section className="assignment-wishes"><div className="panel__head"><div><h2>Желания подопечного</h2><span>Можно забронировать прямо сейчас</span></div><Gift /></div>{data.assignment.wishes.length ? <div>{data.assignment.wishes.map((wish) => <WishCard key={wish.id} wish={wish} profile={data.assignment.user} onChanged={reload} />)}</div> : <EmptyState icon={Heart} title="Открытых желаний нет" text="Напишите анонимно и попросите подсказку." />}</section><section className="santa-chat"><div className="panel__head"><div><h2>Анонимный чат</h2><span>Ваше имя не раскрывается</span></div><LockKeyhole /></div><div className="chat-messages">{data.messages.length ? data.messages.map((item) => <div className={`chat-bubble chat-bubble--${item.direction}`} key={item.id}><span>{item.direction === "out" ? "Вы — Тайный Санта" : "Ваш Тайный Санта"}</span><p>{item.body}</p><small>{formatDate(item.createdAt, { hour: "2-digit", minute: "2-digit" })}</small></div>) : <p className="muted">Спросите про размер, цвет или доставку — анонимно.</p>}</div><form onSubmit={send}><input required placeholder="Написать анонимно…" value={message} onChange={(event) => setMessage(event.target.value)} /><button><Send /></button></form></section></div>}</div>; }

function NotFound() { return <div className="not-found"><Logo /><Gift /><h1>Похоже, эта мечта потерялась</h1><p>Страница не существует или ссылка устарела.</p><Link className="button button--primary" to="/"><span>Вернуться на главную</span></Link></div>; }

export default function App() { return <ToastProvider><SessionProvider><Routes><Route path="/" element={<LandingPage />} /><Route path="/login" element={<AuthPage mode="login" />} /><Route path="/register" element={<AuthPage mode="register" />} /><Route path="/ideas" element={<IdeasPage />} /><Route path="/u/:username" element={<PublicProfile />} /><Route path="/s/:token" element={<PublicProfile shared />} /><Route path="/app/*" element={<ProtectedApp />} /><Route path="*" element={<NotFound />} /></Routes></SessionProvider></ToastProvider>; }
